var SEA_CC={geo:'#378ADD',macro:'#BA7517',crypto:'#3ddc97',pol:'#9b8fef'};
var SEA_KNOWN={
  scheduled:{l:'Scheduled / known',c:'#3ddc97'},
  'outcome-uncertain':{l:'Known date, outcome uncertain',c:'#d9a93f'},
  building:{l:'Building tension',c:'#e89b3c'},
  intervention:{l:'Discretionary intervention',c:'#9b6fd9'},
  surprise:{l:'Surprise shock',c:'#e2645f'},
  'n/a':{l:'Price level',c:'#888'}
};
// Labels used by the chart tooltip and table for the pre/post columns — phrasing
// depends on whether the event was genuinely anticipated (scheduled/building/outcome-uncertain)
// or not (surprise/intervention), since "Pre-event" implies anticipation that didn't exist for shocks.
// "Move after" (not "bounce" or "recovery") is intentionally direction-neutral — a negative
// number there means price continued down, not that the bounce calculation is broken.
var SEA_PREPOST_LABEL={
  scheduled:{pre:'Move into (7d)',post:'Move after (7d)'},
  'outcome-uncertain':{pre:'Move into (7d)',post:'Move after (7d)'},
  building:{pre:'Move into (7d)',post:'Move after (7d)'},
  intervention:{pre:'Move into the decision',post:'Move after the decision'},
  surprise:{pre:'The shock itself',post:'Move after the low/high'},
  'n/a':{pre:'7d before',post:'7d after'}
};
var SEA_CB={geo:'sea-geo',macro:'sea-mac',crypto:'sea-cry',pol:'sea-pol'};
var seaAF='all';

function seaTs(s){return new Date(s).getTime();}
function seaFE(){return seaAF==='all'?SEA_EVENTS:SEA_EVENTS.filter(function(e){return e.cat===seaAF;});}

// ── CHART STATE (pan/zoom, matches backtest price chart) ───────────────────
var seaChartState={offsetX:0,scale:1,dragging:false,dragStartX:0,dragStartOffset:0};
var SEA_BASE_VISIBLE=300;

// ── DRAW ──────────────────────────────────────────────────────────────────
function seaDraw(){
  var cs=seaChartState;
  var wrap=document.getElementById('seaWrap');
  var c=document.getElementById('seaC');
  if(!wrap||!c)return;
  var W=wrap.clientWidth;
  if(!W||W<50)return; // not visible yet — observer will retry
  var H=340;
  var dpr=window.devicePixelRatio||1;
  c.width=W*dpr; c.height=H*dpr;
  c.style.width=W+'px'; c.style.height=H+'px';
  var ctx=c.getContext('2d');
  ctx.setTransform(1,0,0,1,0,0);
  ctx.scale(dpr,dpr);

  var visible=Math.round(SEA_BASE_VISIBLE/cs.scale);
  var startIdx=Math.max(0,Math.floor(cs.offsetX));
  var endIdx=Math.min(SEA_CANDLES.length-1,startIdx+visible);
  var slice=SEA_CANDLES.slice(startIdx,endIdx+1);
  if(!slice.length)return;

  var P={l:8,r:60,t:16,b:30};
  var plotW=W-P.l-P.r, plotH=H-P.t-P.b;

  var minP=Math.min.apply(null,slice.map(function(x){return x.l;}));
  var maxP=Math.max.apply(null,slice.map(function(x){return x.h;}));
  var pRange=(maxP-minP)||1;
  var pad5=pRange*0.06;
  minP-=pad5; maxP+=pad5;
  var range=maxP-minP;

  function yOf(p){return P.t+plotH-((p-minP)/range)*plotH;}
  var candleW=plotW/slice.length;
  var bodyW=Math.max(1,candleW*0.6);
  function xCenter(i){return P.l+(i+0.5)*candleW;} // i = index within slice

  ctx.fillStyle='#0d0f10';ctx.fillRect(0,0,W,H);

  // gridlines + price labels
  var gridLines=5;
  for(var g=0;g<=gridLines;g++){
    var p=minP+(g/gridLines)*range;
    var y=yOf(p);
    ctx.strokeStyle='rgba(255,255,255,0.05)';ctx.lineWidth=0.5;
    ctx.beginPath();ctx.moveTo(P.l,y);ctx.lineTo(P.l+plotW,y);ctx.stroke();
    ctx.fillStyle='#555';ctx.font='10px Inter,sans-serif';ctx.textAlign='left';
    ctx.fillText('$'+Math.round(p).toLocaleString(),P.l+plotW+5,y+3);
  }

  // candles
  slice.forEach(function(cd,i){
    var xc=xCenter(i);
    var isBull=cd.c>=cd.o;
    var col=isBull?'#3ddc97':'#e2645f';
    ctx.strokeStyle=col;ctx.fillStyle=col;ctx.lineWidth=0.8;
    ctx.beginPath();ctx.moveTo(xc,yOf(cd.h));ctx.lineTo(xc,yOf(cd.l));ctx.stroke();
    var yTop=yOf(Math.max(cd.o,cd.c)), yBot=yOf(Math.min(cd.o,cd.c));
    var bodyH=Math.max(1,yBot-yTop);
    if(isBull){ ctx.fillRect(xc-bodyW/2,yTop,bodyW,bodyH); }
    else { ctx.strokeRect(xc-bodyW/2,yTop,bodyW,bodyH); }
  });

  // date labels
  var labelEvery=Math.max(1,Math.floor(visible/6));
  ctx.fillStyle='#555';ctx.font='10px Inter,sans-serif';ctx.textAlign='center';
  slice.forEach(function(cd,i){
    if(i%labelEvery!==0)return;
    var xc=xCenter(i);
    var d=new Date(cd.ts);
    ctx.fillText(d.toISOString().slice(0,7),xc,H-8);
  });

  // event dashed lines — find nearest candle index within slice for each event
  var evts=seaFE();
  seaEventScreenPos=[]; // for tooltip hit-testing
  evts.forEach(function(e){
    var ets=seaTs(e.date);
    if(ets<slice[0].ts||ets>slice[slice.length-1].ts+86400000)return;
    // find closest index
    var bi=0,bd=Infinity;
    slice.forEach(function(cd,i){var d=Math.abs(cd.ts-ets);if(d<bd){bd=d;bi=i;}});
    var xc=xCenter(bi);
    var kc=(SEA_KNOWN[e.known]||{c:'#888'}).c;
    ctx.strokeStyle=kc+'99';ctx.lineWidth=1;ctx.setLineDash([4,3]);
    ctx.beginPath();ctx.moveTo(xc,P.t);ctx.lineTo(xc,P.t+plotH);ctx.stroke();
    ctx.setLineDash([]);
    // marker dot at top
    ctx.beginPath();ctx.arc(xc,P.t+6,4,0,Math.PI*2);
    ctx.fillStyle=kc;ctx.fill();
    ctx.strokeStyle='#0d0f10';ctx.lineWidth=1.2;ctx.stroke();
    seaEventScreenPos.push({x:xc,event:e});
  });
}

var seaEventScreenPos=[];

// ── TABLE ─────────────────────────────────────────────────────────────────
function seaFmtPct(v){
  if(v===null||v===undefined)return '<span style="color:var(--text-faint)">—</span>';
  var c=v>=0?'#3ddc97':'#e2645f';
  return '<span style="color:'+c+'">'+(v>0?'+':'')+v+'%</span>';
}
function seaTable(){
  var tbody=document.getElementById('seaTbody');
  if(!tbody)return;
  var evts=seaFE().slice().sort(function(a,b){return a.date.localeCompare(b.date);});
  tbody.innerHTML=evts.map(function(e){
    var k=SEA_KNOWN[e.known]||{l:'?',c:'#888'};
    return '<tr>'
      +'<td style="color:var(--text-faint);white-space:nowrap;font-size:11px;padding:6px 6px;border-bottom:0.5px solid var(--border)">'+e.date+'</td>'
      +'<td style="font-size:11px;padding:6px 6px;border-bottom:0.5px solid var(--border)">'+e.label
        +'<div style="font-size:10px;color:var(--text-faint);margin-top:2px;line-height:1.4">'+e.note+'</div></td>'
      +'<td style="padding:6px 6px;border-bottom:0.5px solid var(--border)"><span class="'+SEA_CB[e.cat]+'">'
        +(e.cat==='geo'?'Geo':e.cat==='macro'?'Macro':e.cat==='crypto'?'Crypto':'Pol')+'</span></td>'
      +'<td style="padding:6px 6px;border-bottom:0.5px solid var(--border);font-size:10px;color:'+k.c+';white-space:nowrap;">'+k.l+'</td>'
      +'<td style="padding:6px 6px;border-bottom:0.5px solid var(--border);">'+seaFmtPct(e.pre)+'</td>'
      +'<td style="padding:6px 6px;border-bottom:0.5px solid var(--border);">'+seaFmtPct(e.post)+'</td>'
      +'<td style="padding:6px 6px;border-bottom:0.5px solid var(--border);font-size:10px;color:var(--text-dim);white-space:nowrap;">'+e.pat+'</td>'
      +'</tr>';
  }).join('');
}

// ── PAN / ZOOM ────────────────────────────────────────────────────────────
function seaChartWheel(e){
  e.preventDefault();
  var cs=seaChartState;
  var delta=e.deltaY>0?0.85:1.18;
  var newScale=Math.max(0.1,Math.min(10,cs.scale*delta));
  var visible=SEA_BASE_VISIBLE/cs.scale;
  var centerCandle=cs.offsetX+visible/2;
  cs.scale=newScale;
  var newVisible=SEA_BASE_VISIBLE/newScale;
  cs.offsetX=Math.max(0,Math.min(SEA_CANDLES.length-1,centerCandle-newVisible/2));
  seaDraw();
}
function seaChartMouseDown(e){
  var cs=seaChartState;
  cs.dragging=true; cs.dragStartX=e.clientX; cs.dragStartOffset=cs.offsetX;
}
function seaChartMouseMove(e){
  var cs=seaChartState;
  var canvas=document.getElementById('seaC');
  if(!canvas)return;
  var W=canvas.offsetWidth;
  var visible=Math.round(SEA_BASE_VISIBLE/cs.scale);
  if(cs.dragging){
    var dxPx=e.clientX-cs.dragStartX;
    var candlesPerPx=visible/W;
    cs.offsetX=Math.max(0,Math.min(SEA_CANDLES.length-visible,cs.dragStartOffset-dxPx*candlesPerPx));
    seaDraw();
    return;
  }
  // tooltip — find nearest event marker line
  var rect=canvas.getBoundingClientRect();
  var mx=e.clientX-rect.left;
  var tip=document.getElementById('seaTip');
  var hit=null,hd=Infinity;
  seaEventScreenPos.forEach(function(p){
    var d=Math.abs(p.x-mx);
    if(d<hd){hd=d;hit=p;}
  });
  if(hit&&hd<10){
    var cl=hit.event;
    var k=SEA_KNOWN[cl.known]||{l:'?',c:'#888'};
    var lbl=SEA_PREPOST_LABEL[cl.known]||{pre:'Pre-event',post:'Post-event'};
    tip.innerHTML='<b style="color:var(--text)">'+cl.label+'</b><br>'
      +'<span style="color:var(--text-faint);font-size:10px">'+cl.date+'</span><br><br>'
      +'<span style="color:var(--text-faint)">Known beforehand?</span> <b style="color:'+k.c+'">'+k.l+'</b><br>'
      +'<span style="color:var(--text-faint)">'+lbl.pre+'</span> '+seaFmtPct(cl.pre)+'<br>'
      +'<span style="color:var(--text-faint)">'+lbl.post+'</span> '+seaFmtPct(cl.post)+'<br>'
      +'<span style="color:var(--text-faint)">Pattern</span> <b style="color:var(--text-dim);font-size:11px">'+cl.pat+'</b><br><br>'
      +'<span style="color:var(--text-faint);font-size:10px">'+cl.note+'</span>';
    tip.style.display='block';
    var lx=mx+14, ly=e.clientY-rect.top-10;
    if(lx+230>rect.width)lx=mx-240;
    tip.style.left=lx+'px';tip.style.top=ly+'px';
  } else {
    tip.style.display='none';
  }
}
function seaInitChart(){
  var canvas=document.getElementById('seaC');
  if(!canvas)return;
  var wrap=document.getElementById('seaWrap');
  var newCanvas=canvas.cloneNode(false);
  wrap.replaceChild(newCanvas,canvas);
  // zoom to show full range by default
  var cs=seaChartState;
  cs.scale=SEA_BASE_VISIBLE/SEA_CANDLES.length;
  cs.offsetX=0;
  newCanvas.addEventListener('wheel',seaChartWheel,{passive:false});
  newCanvas.addEventListener('mousedown',seaChartMouseDown);
  newCanvas.addEventListener('mousemove',seaChartMouseMove);
  newCanvas.addEventListener('mouseup',function(){seaChartState.dragging=false;});
  newCanvas.addEventListener('mouseleave',function(){
    seaChartState.dragging=false;
    var t=document.getElementById('seaTip');if(t)t.style.display='none';
  });
  newCanvas.style.cursor='crosshair';
  seaDraw();
}

