document.getElementById('seaFilters').addEventListener('click',function(ev){
  var b=ev.target.closest('[data-cat]');if(!b)return;
  seaAF=b.dataset.cat;
  document.querySelectorAll('.sea-fb').forEach(function(x){x.classList.toggle('active',x===b);});
  seaDraw();seaTable();
});

// ── MUTATION OBSERVER — draw as soon as tab becomes visible ───────────────
(function(){
  var tab=document.getElementById('tab-sea-news');
  if(!tab)return;
  var drawn=false;
  function tryDraw(){
    if(drawn)return;
    var wrap=document.getElementById('seaWrap');
    if(wrap&&wrap.clientWidth>50){
      drawn=true;
      seaInitChart();seaTable();
    }
  }
  var obs=new MutationObserver(function(mutations){
    mutations.forEach(function(m){
      if(m.type==='attributes'&&m.attributeName==='class'){
        if(tab.classList.contains('active')){
          drawn=false; // allow redraw on each open
          requestAnimationFrame(function(){requestAnimationFrame(tryDraw);});
        }
      }
    });
  });
  obs.observe(tab,{attributes:true});
  window.addEventListener('resize',function(){if(tab.classList.contains('active'))seaDraw();});
})();

