function fomcPct(a,b){return ((b-a)/a*100).toFixed(1);}

function fomcInit(){
  // stats cards
  var el=document.getElementById('fomcStats');
  if(el){
    var drops=FOMC_DATA.filter(function(d){return parseFloat(fomcPct(d.btc,d.post))<0;});
    var avgPost=FOMC_DATA.reduce(function(s,d){return s+parseFloat(fomcPct(d.btc,d.post));},0)/FOMC_DATA.length;
    var avgPre=FOMC_DATA.reduce(function(s,d){return s+parseFloat(fomcPct(d.pre,d.btc));},0)/FOMC_DATA.length;
    var stats=[
      {l:'Meetings analysed',v:FOMC_DATA.length,c:'var(--text)'},
      {l:'Post-FOMC drops',v:drops.length+' of '+FOMC_DATA.length+' ('+(Math.round(drops.length/FOMC_DATA.length*100))+'%)',c:'#e2645f'},
      {l:'Avg 10d pre-move',v:(avgPre>=0?'+':'')+avgPre.toFixed(1)+'%',c:avgPre>=0?'#3ddc97':'#e2645f'},
      {l:'Avg 3d post-move',v:(avgPost>=0?'+':'')+avgPost.toFixed(1)+'%',c:avgPost>=0?'#3ddc97':'#e2645f'},
    ];
    el.innerHTML=stats.map(function(s){
      return '<div style="background:var(--bg1);border-radius:8px;padding:12px 14px;border:0.5px solid var(--border)">'
        +'<div style="font-size:10px;color:var(--text-faint);margin-bottom:4px">'+s.l+'</div>'
        +'<div style="font-size:20px;font-weight:500;color:'+s.c+'">'+s.v+'</div></div>';
    }).join('');
  }
  // table
  var tbody=document.getElementById('fomcTbody');
  if(tbody){
    tbody.innerHTML=FOMC_DATA.slice().reverse().map(function(d){
      var prePct=fomcPct(d.pre,d.btc), postPct=fomcPct(d.btc,d.post);
      return '<tr>'
        +'<td style="padding:6px 8px;border-bottom:0.5px solid var(--border);white-space:nowrap;font-size:11px;color:var(--text-faint)">'+d.date+'</td>'
        +'<td style="padding:6px 8px;border-bottom:0.5px solid var(--border);font-size:11px">'+d.dec+'</td>'
        +'<td style="padding:6px 8px;border-bottom:0.5px solid var(--border);text-align:right;font-size:11px">$'+d.btc.toLocaleString()+'</td>'
        +'<td style="padding:6px 8px;border-bottom:0.5px solid var(--border);text-align:right;font-size:11px;color:'+(parseFloat(prePct)>=0?'#3ddc97':'#e2645f')+'">'+(parseFloat(prePct)>=0?'+':'')+prePct+'%</td>'
        +'<td style="padding:6px 8px;border-bottom:0.5px solid var(--border);text-align:right;font-size:11px;color:'+(parseFloat(postPct)>=0?'#3ddc97':'#e2645f')+'">'+(parseFloat(postPct)>=0?'+':'')+postPct+'%</td>'
        +'<td style="padding:6px 8px;border-bottom:0.5px solid var(--border);font-size:11px;color:var(--text-faint)">'+d.note+'</td>'
        +'</tr>';
    }).join('');
  }
  // patterns
  var pel=document.getElementById('fomcPatterns');
  if(pel){
    var pats=[
      {t:'The pre-FOMC squeeze',b:'Leveraged longs build in the 10 days before the decision. Open interest peaks. Whether the news is good or bad, the unwind triggers a liquidation cascade. Average pre-FOMC move: +4% into the decision.'},
      {t:'Post-FOMC dump (regardless of outcome)',b:'BTC dropped after 8 of 9 FOMC meetings in 2025. Hold, cut, or hike — the positioning unwind happens either way. Average post-decision move: ~-6% over 3 days.'},
      {t:'The exception: genuine surprise or dominant narrative',b:'The only post-FOMC rallies came when the Fed surprised (Sept 2024 50bp cut) or when an external narrative dominated (Nov 2024 Trump win, Nov 2023 ETF anticipation). Without an override, expect the dump.'},
      {t:'Trading implication',b:'Avoid adding longs in the 3-5 days before FOMC. If long, reduce into the meeting. Post-FOMC dips are historically good entries if the macro trend is still bullish.'},
    ];
    pel.innerHTML=pats.map(function(p){
      return '<div style="padding:10px 12px;background:var(--bg2);border-radius:6px;border:0.5px solid var(--border)">'
        +'<div style="font-size:11px;font-weight:500;color:var(--text);margin-bottom:6px">'+p.t+'</div>'
        +'<div style="font-size:11px;color:var(--text-faint);line-height:1.6">'+p.b+'</div></div>';
    }).join('');
  }
}

