// ── AI OPINION ────────────────────────────────────────────────────────────
async function aiAskOpinion(){
  var type=document.getElementById('aiEventType').value;
  var reaction=document.getElementById('aiPriceReaction').value.trim();
  var desc=document.getElementById('aiEventDesc').value.trim();
  if(!reaction||!desc){alert('Fill in the price reaction and event description.');return;}
  var typeLabels={
    surprise_bearish:'Surprise shock (bearish) — war, collapse, ban',
    surprise_bullish:'Surprise shock (bullish) — unexpected deal or policy',
    known_bearish:'Known/anticipated bearish event — rate hike',
    known_bullish:'Known/anticipated bullish event — rate cut, ETF approval',
    geopolitical:'Geopolitical escalation',
    geopolitical_de:'Geopolitical de-escalation / peace deal',
    crypto_specific:'Crypto-specific event',
  };
  var hist='HISTORICAL PATTERNS:\n'
    +'Surprise bearish shocks (war/crash/ban): dump fast then 100% recovery rate IF no fundamental damage to BTC.\n'
    +'Known bullish events (ETF/halving/inauguration): price runs up pre-event, sells off on the news.\n'
    +'Known bearish events (rate hikes): price drops and keeps dropping as liquidity drains.\n'
    +'Geopolitical de-escalation: pop on announcement, then sell the news on formal signing.\n'
    +'Recovery speed increasing over time as institutional ETF flows buffer panic selling.\n'
    +'KEY RULE: The event is never the trade. What happens to LIQUIDITY after determines whether gains hold.\n';
  var prompt='You are a crypto market analyst. Use this historical data:\n\n'+hist
    +'\nCURRENT EVENT:\nType: '+typeLabels[type]+'\nDescription: '+desc+'\nPrice reaction: '+reaction
    +'\n\nGive a SHORT direct opinion (max 200 words) on:\n1. Most likely price direction next 1-7 days\n2. Key thing to watch\n3. Biggest risk to the thesis';
  var btn=document.querySelector('[onclick="aiAskOpinion()"]');
  var res=document.getElementById('aiResult');
  var txt=document.getElementById('aiResultText');
  btn.textContent='Thinking...';btn.disabled=true;res.style.display='none';
  try{
    var r=await fetch('https://royal-darkness-0ac6.wimneys.workers.dev/v1/messages',{
      method:'POST',
      headers:{'Content-Type':'application/json'},
      body:JSON.stringify({model:'claude-sonnet-4-5',max_tokens:400,messages:[{role:'user',content:prompt}]})
    });
    var data=await r.json();
    txt.textContent=(data.content||[]).map(function(b){return b.text||'';}).join('')||'No response.';
    res.style.display='block';
  }catch(e){txt.textContent='Error: '+e.message;res.style.display='block';}
  btn.textContent='Ask AI for opinion';btn.disabled=false;
}
